// O(1) slug → area lookup (built once at module level)
export const areaBySlug = new Map<string, ServiceArea>(serviceAreas.map(a => [a.slug, a]));

// Helper: get nearby areas as full objects
export function getNearbyAreas(slug: string, limit = 4): ServiceArea[] {
  const area = areaBySlug.get(slug);
  if (!area) return [];
  return area.nearbySlug
    .slice(0, limit)
    .map(s => areaBySlug.get(s))
    .filter(Boolean) as ServiceArea[];
}

// Helper: get all slugs for generateStaticParams
export function getAllSlugs(): string[] {
  return serviceAreas.map(a => a.slug);
}

// Featured priority areas (top 10)
export const featuredAreas = serviceAreas
  .filter(a => a.priority === 5)
  .slice(0, 10);
